#include <bits/stdc++.h>
using namespace std;
int n,q;
struct node
{
	int num;
	int id;	
} a[8005];
int t[8005];
bool fun(node x,node y)
{
	if(x.num!=y.num) return x.num<y.num;
	return x.id<y.id;
}
int main()
{
	cin>>n>>q;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i].num;
		a[i].id=i; 
	}
	sort(a+1,a+1+n,fun);
	for(int i=1;i<=n;i++) t[a[i].id]=i;
	while(q--)
	{
		int op;
		cin>>op;
		if(op==1)
		{
			int x;
			int v;
			cin>>x>>v;
			int t1=a[t[x]].num;
			a[t[x]].num=v;
			if(t1<v)
			{
				for(int i=t[x]+1;i<=n;i++)
				{
					if(fun(a[i],a[i-1])) swap(a[i],a[i-1]);
					else break;
				}
			}
			else
			{
				for(int i=t[x]-1;i>=1;i--)
				{
					if(fun(a[i+1],a[i])) swap(a[i],a[i+1]);
					else break;
				}
			}
			for(int i=1;i<=n;i++) t[a[i].id]=i;
		}
		else
		{
			int x;
			cin>>x;
			cout<<t[x]<<'\n';
		}
	}
	return 0;
}
